// Quantum Coherence Monitor — QTP-AFTO v4.3.2 (Databricks -> Supabase port)
// Read-only Alpaca (optional, staticData creds). Telemetry INSERTs are built here as
// __supabase_insert_sql and executed by the downstream "Write Supabase Telemetry" Postgres node.
// No order, model, size, or gate changes. No $env / $vars (denied on n8n cloud — root cause of the v4.2.1 silent no-op).
const startedAt = new Date();
const runId = `qtp_afto_${startedAt.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}`;

// --- NYSE holiday / weekend guard (v4.3.2) ---
const NYSE_HOLIDAYS_2026 = ['2026-01-01','2026-01-19','2026-02-16','2026-04-03','2026-05-25','2026-06-19','2026-07-03','2026-09-07','2026-11-26','2026-12-25'];
const _etNow = new Date(new Date().toLocaleString('en-US',{timeZone:'America/New_York'}));
const _etDateStr = _etNow.getFullYear()+'-'+String(_etNow.getMonth()+1).padStart(2,'0')+'-'+String(_etNow.getDate()).padStart(2,'0');
const marketHoliday = NYSE_HOLIDAYS_2026.includes(_etDateStr) || _etNow.getDay()===0 || _etNow.getDay()===6;

// --- Metrics from "Fetch Quantum Metrics" (Supabase quantum.*) ---
const m = $input.first().json || {};
const deadLetters = Number(m.dead_letters ?? 0);
const scannerSignals = Number(m.scanner_signals ?? 0);
const vcObsToday = Number(m.vc_obs_today ?? 0);
// v_risk_gate_status / v_current_position_risk_state were NOT migrated to Supabase:
const unprotectedKnown = false;
const unprotected = 0; // degraded input — cannot trigger a pause advisory

// --- Optional secrets from workflow staticData (never hardcoded; $env is denied on n8n cloud) ---
const sd = $getWorkflowStaticData('global') || {};
const cred = sd._credentials || {};
const alpacaKey = cred.alpaca_api_key || cred.ALPACA_API_KEY || cred.alpaca_key_id || '';
const alpacaSecret = cred.alpaca_secret_key || cred.ALPACA_SECRET_KEY || cred.alpaca_secret || '';
const alpacaBase = String(cred.alpaca_base_url || 'https://paper-api.alpaca.markets').replace(/\/+$/, '');

let alpacaStatus = 'UNAVAILABLE_NO_CRED';
let positionsCount = null;
let openOrdersCount = null;
let tradingBlocked = null; // unknown unless Alpaca reachable
if (alpacaKey && alpacaSecret) {
  const alp = async (path) => await this.helpers.httpRequest({
    method: 'GET', url: alpacaBase + path,
    headers: { 'APCA-API-KEY-ID': alpacaKey, 'APCA-API-SECRET-KEY': alpacaSecret },
    json: true, timeout: 30000,
  });
  try {
    const [account, positions, openOrders] = await Promise.all([
      alp('/v2/account'), alp('/v2/positions'), alp('/v2/orders?status=open&limit=500')
    ]);
    alpacaStatus = account.status || 'UNKNOWN';
    positionsCount = positions.length;
    openOrdersCount = openOrders.length;
    tradingBlocked = account.trading_blocked === true || account.account_blocked === true;
  } catch (e) {
    alpacaStatus = 'ERROR: ' + String((e && e.message) || e).slice(0, 180);
  }
}

// --- Market-session calc (NY), preserved from v4.2.1 ---
const ny = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
const after0940 = (ny.getHours() > 9) || (ny.getHours() === 9 && ny.getMinutes() >= 40);
// QTP_AFTO_v4.3.2_20260706: zero-signal advisory only valid DURING the session.
// After 16:00 ET zero signals are normal — v4.3.1 spammed pause advisories all evening.
const before1600 = ny.getHours() < 16;
const inSession = after0940 && before1600;

// --- Pause advisory: v4.2.1 condition preserved; degraded (UNKNOWN) inputs cannot trigger ---
const pause = (!marketHoliday && inSession && scannerSignals === 0) || deadLetters > 0 || unprotected > 0 || tradingBlocked === true;
const afterHoursSuppressedZeroSignals = !marketHoliday && after0940 && !before1600 && scannerSignals === 0 && !pause;
const holidaySuppressedZeroSignals = marketHoliday && after0940 && scannerSignals === 0 && !pause;
const degraded = [];
if (!unprotectedKnown) degraded.push('unprotected_positions=UNKNOWN(v_risk_gate_status not in Supabase)');
if (tradingBlocked === null) degraded.push('trading_blocked=UNKNOWN(alpaca=' + alpacaStatus + ')');
const reason = (pause
  ? `pause_advisory: scannerSignals=${scannerSignals}, deadLetters=${deadLetters}, unprotected=${unprotected}, tradingBlocked=${tradingBlocked === true}`
  : (afterHoursSuppressedZeroSignals ? 'nominal_after_hours: zero-signal leg suppressed (session closed)' : holidaySuppressedZeroSignals ? 'nominal_holiday: zero-signal leg suppressed (marketHoliday=true)' : 'nominal')) + ` | marketHoliday=${marketHoliday}` + (degraded.length ? ' | degraded: ' + degraded.join('; ') : '');

// --- SQL builders (Postgres: single-quote doubling only) ---
function esc(v) { if (v === undefined || v === null) return 'NULL'; return "'" + String(v).replace(/'/g, "''").slice(0, 20000) + "'"; }
function bl(v) { return v === true ? 'true' : 'false'; }

const telemetryNotes = `positions=${positionsCount === null ? 'NA' : positionsCount}; open_orders=${openOrdersCount === null ? 'NA' : openOrdersCount}; vc_shadow_obs_today=${vcObsToday}`
  + (degraded.length ? '; ' + degraded.join('; ') : '') + '; QTP_AFTO_SUPABASE_PORT_v4.3.2';

const sqlParts = [];
sqlParts.push(`INSERT INTO quantum.telegram_grok_heartbeat
(heartbeat_id, checked_at, workflow_id, workflow_name, latest_execution_at, latest_status, success_last10, error_last10, telegram_test_status, notes)
VALUES (${esc(runId)}, now(), 'AaaQOrBVEXwJkOyz', 'Quantum Coherence Heartbeat & Preopen Monitor - QTP-AFTO', now(), 'HEARTBEAT_LOGGED_BY_QTP_AFTO', '1', '0', 'NOT_SENT_ON_SCHEDULED_HEARTBEAT', ${esc('15-min coherence heartbeat row; sink migrated Databricks->Supabase. QTP_AFTO_SUPABASE_PORT_v4.3.2')});`);
sqlParts.push(`INSERT INTO quantum.infra_telemetry_15m
(telemetry_id, checked_at, gpu_load_pct, tpu_load_pct, container_health, databricks_sql_status, n8n_api_status, alpaca_status, notes)
VALUES (${esc(runId)}, now(), NULL, NULL, 'N8N_WORKFLOW_ACTIVE', 'MIGRATED_TO_SUPABASE', 'OK', ${esc(alpacaStatus)}, ${esc(telemetryNotes)});`);
sqlParts.push(`INSERT INTO quantum.entry_pause_control
(control_id, checked_at, pause_new_entries, reason, scanner_signal_count, dead_letters, unprotected_positions, trading_blocked, status, source, expires_at)
VALUES (${esc(runId)}, now(), ${bl(pause)}, ${esc(reason)}, ${esc(String(scannerSignals))}, ${esc(String(deadLetters))}, ${esc(unprotectedKnown ? String(unprotected) : 'UNKNOWN')}, ${bl(tradingBlocked === true)}, ${esc(pause ? 'PAUSE_ADVISORY_LOGGED' : (afterHoursSuppressedZeroSignals ? 'NOMINAL_AFTER_HOURS' : (holidaySuppressedZeroSignals ? 'NOMINAL_HOLIDAY' : 'NOMINAL')))}, 'qtp_afto_monitor', now() + interval '30 minutes');`);
const __supabase_insert_sql = sqlParts.join('\n');

const alert_text = `⚠️ QTP-AFTO pause advisory\n${reason}\nNo live order logic was changed by this monitor.`;

return [{ json: {
  run_id: runId,
  pause_advisory: pause,
  reason,
  scannerSignals,
  deadLetters,
  unprotected_positions: unprotectedKnown ? unprotected : 'UNKNOWN',
  tradingBlocked,
  alpaca_status: alpacaStatus,
  positions: positionsCount,
  openOrders: openOrdersCount,
  alert_text,
  __supabase_insert_sql,
} }];
